const body = $input.first().json.body || $input.first().json;
const sourceType = body.source_type || 'url';
const url = body.url || '';
const brandName = body.brand_name || 'Unknown Brand';
return [{ json: { sourceType, url, brandName } }];

const { jinaText, screenshotB64, hasScreenshot } = $input.first().json;
const { brandName, url, sourceType } = $('Extrair Input').first().json;

const systemPrompt = `És um analista sénior de identidade de marca e especialista em design systems. A tua missão é extrair um Brand Style Profile (BSP) completo e rigoroso.

REGRAS DE EXTRAÇÃO:
1. CORES: Extrai hex codes REAIS do CSS, estilos inline ou elementos visuais visíveis. Nunca uses #000000/#ffffff como placeholder — se a marca usar preto/branco puro, indica-o explicitamente. Fornece mínimo 6 cores.
2. TIPOGRAFIA: Identifica nomes reais de fontes (Google Fonts, Adobe Fonts, fontes do sistema). Procura declarações font-family, @import, ou referências Typekit.
3. TOM DE VOZ: Extrai frases reais da página — headlines, CTAs, taglines, descrições de produto. Mínimo 5 sample_phrases reais, não inventadas.
4. ESTILO VISUAL: Analisa a linguagem visual — editorial/lifestyle/produto/minimalista/bold? Que cores dominam as imagens? Qual é o estilo de composição?
5. STYLE_ANCHOR_PROMPT: Gera um parágrafo de 200 palavras que descreve o estilo visual completo da marca de forma tão precisa que qualquer modelo de geração de imagem pode replicar esta identidade visual apenas com este parágrafo. Inclui: paleta com hex codes e papéis, estilo de iluminação e temperatura de cor, regras de composição, texturas e materiais, tratamento tipográfico, mood geral. Escreve como um brief de diretor de arte profissional.
6. REFERENCE_IMAGES: Array com descrições textuais das imagens de referência que melhor representam o estilo visual da marca (extraídas do conteúdo analisado).

OUTPUT: JSON válido apenas, sem markdown. Schema exato:
{
  "brand_name": "string",
  "source": { "type": "url", "ref": "string" },
  "palette": {
    "primary": "#hex", "secondary": "#hex", "accent": "#hex",
    "neutral": "#hex", "background": "#hex", "text": "#hex",
    "extra": ["#hex"]
  },
  "typography": {
    "heading_font": "Nome da Fonte", "body_font": "Nome da Fonte",
    "weights": ["400","600","700"], "scale": "1.25"
  },
  "logo": { "url": null, "variants": ["primary","reversed"], "clear_space": "descrição" },
  "tone_of_voice": {
    "adjectives": ["palavra1","palavra2","palavra3","palavra4","palavra5"],
    "do": ["regra1","regra2","regra3","regra4"],
    "dont": ["regra1","regra2","regra3","regra4"],
    "sample_phrases": ["Frase real da página 1","Frase real da página 2","Frase real da página 3","Frase real da página 4","Frase real da página 5"]
  },
  "imagery_style": {
    "description": "Descrição de 2 frases do estilo fotográfico/visual da marca",
    "composition_rules": ["regra1 (ex: sujeito centrado com 40% espaço negativo)","regra2","regra3"],
    "filters": "descrição do color grading e tratamento (ex: tom quente desaturado estilo film, alto contraste frio, limpo e luminoso)"
  },
  "layout_patterns": {
    "grid": "12-col / 6-col / fluid",
    "spacing": "compact / comfortable / generous",
    "alignment": "left / center / right",
    "recurring_elements": ["hero banner","grid de cartões","imagem full-bleed"]
  },
  "platforms": {
    "instagram": { "aspect_ratios": ["1:1","9:16"], "post_types": ["produto","lifestyle","citação"] },
    "linkedin": { "aspect_ratios": ["1.91:1","1:1"], "post_types": ["artigo","anúncio"] }
  },
  "style_anchor_prompt": "Parágrafo de 200 palavras para uso direto em prompts de imagem — descreve estilo fotográfico completo, paleta com hex e papéis, iluminação técnica, composição, texturas, mood",
  "reference_images": ["Descrição imagem de referência 1","Descrição imagem de referência 2","Descrição imagem de referência 3"]
}`;

const userContent = [];

if (hasScreenshot && screenshotB64) {
  userContent.push({
    type: 'image_url',
    image_url: { url: `data:image/jpeg;base64,${screenshotB64}`, detail: 'high' }
  });
  userContent.push({
    type: 'text',
    text: `Marca: ${brandName}\nURL: ${url}\n\nO screenshot acima mostra o website da marca. Analisa VISUALMENTE as cores reais, estilo fotográfico, composição, tipografia e identidade visual.\n\nConteúdo de texto extraído da página:\n${jinaText.slice(0, 8000)}\n\nExtrai o BSP completo combinando a análise visual do screenshot COM o conteúdo de texto.`
  });
} else {
  userContent.push({
    type: 'text',
    text: `Marca: ${brandName}\nURL: ${url}\n\nConteúdo da página web:\n${jinaText}\n\nExtrai o BSP completo. Faz inferências precisas e profissionais onde os dados não são explícitos.`
  });
}

const payload = {
  model: 'gpt-4o',
  max_tokens: 4096,
  response_format: { type: 'json_object' },
  messages: [{ role: 'system', content: systemPrompt }, { role: 'user', content: userContent }]
};
return [{ json: { payload, brandName, url, sourceType } }];

const openAiResp = $input.first().json;
const meta = $('Montar Payload OpenAI').first().json;
const rawText = openAiResp.choices?.[0]?.message?.content || '';
if (!rawText) throw new Error('OpenAI empty: ' + JSON.stringify(openAiResp).slice(0,200));
let bsp;
try { bsp = JSON.parse(rawText); } catch(e) { throw new Error('BSP parse failed: ' + rawText.slice(0,200)); }
bsp.brand_name = bsp.brand_name || meta.brandName;
bsp.source = bsp.source || { type: meta.sourceType, ref: meta.url };
const supabasePayload = { brand_name: bsp.brand_name, source: bsp.source || {}, palette: bsp.palette || {}, typography: bsp.typography || {}, logo: bsp.logo || {}, tone_of_voice: bsp.tone_of_voice || {}, imagery_style: bsp.imagery_style || {}, layout_patterns: bsp.layout_patterns || {}, platforms: bsp.platforms || {} };
return [{ json: { bsp, supabasePayload } }];

const saved = $input.first().json;
const record = Array.isArray(saved) ? saved[0] : saved;
const bsp = $('Parsear BSP').first().json.bsp;
return [{ json: { brand: { ...bsp, id: record.id, created_at: record.created_at, updated_at: record.updated_at } } }];

const { url } = $('Extrair Input').first().json;
const jinaRaw = $input.first().json;
const jinaText = typeof jinaRaw.data === 'string' ? jinaRaw.data : JSON.stringify(jinaRaw);

// Configura SCREENSHOTONE_KEY em n8n Settings → Environment Variables para ativar screenshots
// Regista gratuitamente em screenshotone.com — free tier com 100 capturas/mês
const SCREENSHOT_KEY = process.env.SCREENSHOTONE_KEY || '';
let screenshotB64 = null;

if (SCREENSHOT_KEY) {
  try {
    const sUrl = `https://api.screenshotone.com/take?access_key=${SCREENSHOT_KEY}&url=${encodeURIComponent(url)}&format=jpg&viewport_width=1440&viewport_height=900&block_ads=true&cache=true&delay=2&image_quality=80`;
    const resp = await fetch(sUrl, { signal: AbortSignal.timeout(30000) });
    if (resp.ok && (resp.headers.get('content-type') || '').startsWith('image/')) {
      const buf = await resp.arrayBuffer();
      screenshotB64 = Buffer.from(buf).toString('base64');
    }
  } catch (_) { /* screenshot opcional — falha silenciosa */ }
}

return [{ json: { jinaText: jinaText.slice(0, 14000), screenshotB64, hasScreenshot: !!screenshotB64 } }];

const body = $input.first().json.body || $input.first().json;
const brandId = body.brand_id || '';
const theme = body.theme || '';
const platform = body.platform || 'Instagram';
const goal = body.goal || 'Engagement';
const extraContext = body.extra_context || '';
if (!brandId) throw new Error('brand_id is required');
return [{ json: { brandId, theme, platform, goal, extraContext } }];

const inputs = $('Extrair Input').first().json;
const supaResp = $input.first().json;
const bsp = Array.isArray(supaResp) ? supaResp[0] : supaResp;
if (!bsp || !bsp.brand_name) throw new Error('BSP não encontrado para id: ' + inputs.brandId);

const tov = bsp.tone_of_voice || {};
const img = bsp.imagery_style || {};
const p   = bsp.palette || {};

const styleAnchor = bsp.style_anchor_prompt ||
  `Marca: ${bsp.brand_name}. Paleta: primária ${p.primary||'N/A'}, secundária ${p.secondary||'N/A'}, accent ${p.accent||'N/A'}, fundo ${p.background||'N/A'}. Imagem: ${img.description||'fotografia comercial profissional'}. Composição: ${(img.composition_rules||[]).join(', ')||'profissional'}. Tratamento: ${img.filters||'limpo, nítido, profissional'}.`;

const platformRules = {
  Instagram: 'Máx 2200 caract. Hook na PRIMEIRA linha (sem emoji até linha 2). 3-5 hashtags agrupados no fim. Parágrafos curtos com espaço entre eles. Primeiros 125 caract. devem funcionar sozinhos como preview.',
  LinkedIn:  'Profissional mas humano. Máx 1500 caract. Máx 3 hashtags. Abre com insight ou afirmação contraintuitiva. Sem clichés motivacionais.',
  TikTok:    'Conversacional, soa a fala não a texto. Hook nas primeiras 3 palavras. Máx 300 caract. 1 hashtag no máximo.',
  'Twitter/X': 'Máx 280 caract. Direto, provocador ou útil. 1 hashtag máximo ou nenhum.'
};
const rule = platformRules[inputs.platform] || 'Adapta às normas da plataforma.';

const hashtagRules = `HASHTAGS — REGRAS OBRIGATÓRIAS:
- NUNCA usar hashtags genéricas (#marketing #business #entrepreneur #success)
- Usar apenas hashtags específicas ao nicho da marca: setor, produto, comunidade
- Exemplos CORRETOS para uma marca de fitness: #treino #musculacao #nutrição (não #fitness #gym #health)
- Exemplos CORRETOS para uma marca de tech: #startuptech #desenvolvedores #ux (não #technology #innovation)
- Máximo 5 hashtags — qualidade sobre quantidade`;

const systemPrompt = `És um copywriter sénior de redes sociais especializado em conteúdo de marca para o mercado português. Escreves em PORTUGUÊS EUROPEU (pt-PT) — nunca em pt-BR, nunca em inglês.

IDENTIDADE DE MARCA:
Marca: ${bsp.brand_name}
Tom de voz: ${(tov.adjectives||[]).join(', ')}

FAZER (obrigatório — todos os posts seguem TODAS estas regras):
${(tov.do||[]).join('\n')}

NÃO FAZER (violação = falha):
${(tov.dont||[]).join('\n')}

REFERÊNCIAS DE VOZ — as legendas devem soar como estas frases:
${(tov.sample_phrases||[]).join('\n')}

IDENTIDADE VISUAL:
${styleAnchor}

PLATAFORMA: ${inputs.platform}
REGRAS: ${rule}

${hashtagRules}

TAREFA:
Tema: ${inputs.theme}
Objetivo: ${inputs.goal}
Formato: ${inputs.format||'Post simples'}
Contexto extra: ${inputs.extraContext||'nenhum'}

Gera 3 variações de legenda com ângulos diferentes:
1. EMOCIONAL — apela à emoção, aspiração ou identidade do utilizador
2. INFORMATIVO — entrega um facto, dica ou insight concreto
3. PROVOCADOR — faz uma afirmação ousada, pergunta ou desafio que gera debate

Para cada variação, gera também um visual_concept de 3 frases exatas:
Frase 1: Estilo fotográfico (fotografia de produto comercial / lifestyle editorial / etc.) e descrição do sujeito com materiais e texturas.
Frase 2: Setup de iluminação — key light (direção, tipo, temperatura em Kelvin, ex: 45° superior esquerdo, softbox grande, 5500K) e especificação da câmara (focal length mm, abertura f/).
Frase 3: "As ÚNICAS cores presentes são: primária ${p.primary||'N/A'} como [papel], secundária ${p.secondary||'N/A'} como [papel], accent ${p.accent||'N/A'} como [papel]. ${(img.composition_rules||['composição profissional']).join(', ')}. Tratamento: ${img.filters||'limpo profissional'}."

OUTPUT — JSON válido apenas, sem markdown:
{
  "caption": "legenda principal (variação emocional)",
  "hashtags": ["#tag_especifica1","#tag_especifica2","#tag_especifica3"],
  "cta": "chamada para ação",
  "visual_concept": "brief visual de 3 frases com specs de iluminação e hex codes da paleta",
  "variations": {
    "emocional":   { "caption": "...", "hashtags": ["..."], "visual_concept": "..." },
    "informativo": { "caption": "...", "hashtags": ["..."], "visual_concept": "..." },
    "provocador":  { "caption": "...", "hashtags": ["..."], "visual_concept": "..." }
  }
}`;

const userMessage = `Tema: ${inputs.theme}\nPlataforma: ${inputs.platform}\nObjetivo: ${inputs.goal}` +
  (inputs.extraContext ? `\nContexto extra: ${inputs.extraContext}` : '');

const payload = {
  model: 'gpt-4o',
  max_tokens: 3000,
  response_format: { type: 'json_object' },
  messages: [{ role: 'system', content: systemPrompt }, { role: 'user', content: userMessage }]
};
return [{ json: { payload, brandId: inputs.brandId, bspName: bsp.brand_name } }];

const openAiResp = $input.first().json;
const rawText = openAiResp.choices?.[0]?.message?.content || '';
if (!rawText) throw new Error('OpenAI empty response');
let result;
try { result = JSON.parse(rawText); }
catch(e) { throw new Error('JSON parse failed: ' + rawText.slice(0,200)); }
return [{ json: {
  caption: result.caption || '',
  hashtags: result.hashtags || [],
  cta: result.cta || '',
  visual_concept: result.visual_concept || '',
  variations: result.variations || {}
} }];

const body = $input.first().json.body || $input.first().json;
const brandId = body.brand_id || ''; if (!brandId) throw new Error('brand_id required');
const concept = body.concept || 'Brand social media post';
const textOverlay = body.text_overlay || '';
const aspectRatio = body.aspect_ratio || '1:1 (Feed)';
return [{ json: { brandId, concept, textOverlay, aspectRatio } }];

const rawBsp = $input.first().json;
const bsp = Array.isArray(rawBsp) ? rawBsp[0] : rawBsp;
if (!bsp || !bsp.brand_name) throw new Error('Brand not found');
const p = bsp.palette || {};
const img = bsp.imagery_style || {};
const lay = bsp.layout_patterns || {};
const typ = bsp.typography || {};
const tov = bsp.tone_of_voice || {};
const inputs = $('Extrair Input').first().json;
const extraColors = (p.extra || []).map((c, i) => `Extra${i+1}: ${c}`).join(', ');
const paletteStr = `Primary: ${p.primary||'N/A'} | Secondary: ${p.secondary||'N/A'} | Accent: ${p.accent||'N/A'} | Background: ${p.background||'N/A'} | Neutral: ${p.neutral||'N/A'} | Text: ${p.text||'N/A'}${extraColors ? ' | '+extraColors : ''}`;
const styleAnchor = `BRAND: ${bsp.brand_name}\nCOLOR PALETTE (ONLY THESE HEX CODES — NO EXCEPTIONS): ${paletteStr}\nIMAGERY: ${img.description||'clean professional commercial photography'}\nCOMPOSITION RULES: ${(img.composition_rules||[]).join(' | ')||'professional composition'}\nVISUAL TREATMENT: ${img.filters||'clean, sharp, professional'}\nLAYOUT: ${lay.grid||'flexible'} | spacing: ${lay.spacing||'generous'} | alignment: ${lay.alignment||'left'}\nTYPOGRAPHY: ${typ.heading_font||'sans-serif'} (${(typ.weights||['400','700']).join('/')})\nTONE: ${(tov.adjectives||[]).join(', ')}`;
return [{ json: { bsp, styleAnchor, ...inputs } }];

const enhancedPrompt = $input.first().json.choices?.[0]?.message?.content || '';
if (!enhancedPrompt) throw new Error('GPT-4o Enhancer devolveu resposta vazia');
const inputs = $('Extrair Input').first().json;
const sizeMap = {
  '1:1 (Feed)': '1024x1024',
  '9:16 (Story/Reel)': '1024x1792',
  '16:9 (Landscape)': '1792x1024',
  '4:5 (Feed vertical)': '1024x1280'
};
const size = sizeMap[inputs.aspectRatio] || '1024x1024';
const payload = { model: 'gpt-image-2', prompt: enhancedPrompt, n: 1, size, quality: 'high' };
return [{ json: { payload, enhancedPrompt } }];

const resp = $input.first().json;
const b64 = resp.data?.[0]?.b64_json || '';
if (!b64) throw new Error('No b64_json in OpenAI response: ' + JSON.stringify(resp).slice(0,200));
const filename = `brand-image-${Date.now()}.png`;
return [{
  json: { filename },
  binary: {
    data: { data: b64, mimeType: 'image/png', fileName: filename, fileExtension: 'png' }
  }
}];

const fileId = $('Subir para Drive').first().json.id;
if (!fileId) throw new Error('No file id from Drive: ' + JSON.stringify($('Subir para Drive').first().json).slice(0,200));
return [{ json: {
  image_url:    `https://drive.google.com/thumbnail?id=${fileId}&sz=w1024`,
  viewLink:     `https://drive.google.com/file/d/${fileId}/view?usp=sharing`,
  downloadLink: `https://drive.google.com/uc?export=download&id=${fileId}`,
  fileId
} }];

const body = $input.first().json.body || $input.first().json;
const brandId = body.brand_id || ''; if (!brandId) throw new Error('brand_id required');
const topic = body.topic || 'Brand tips';
const numSlides = parseInt(body.num_slides || '5');
const platform = body.platform || 'Instagram';
return [{ json: { brandId, topic, numSlides, platform } }];

const inputs = $('Extrair Input').first().json;
const bsp = ($input.first().json || [])[0] || $input.first().json;
if (!bsp || !bsp.brand_name) throw new Error('BSP não encontrado');

const tov = bsp.tone_of_voice || {};
const img = bsp.imagery_style || {};
const p   = bsp.palette || {};

const styleAnchor = bsp.style_anchor_prompt ||
  `Marca: ${bsp.brand_name}. Paleta: primária ${p.primary||'N/A'}, secundária ${p.secondary||'N/A'}, accent ${p.accent||'N/A'}. Imagem: ${img.description||'fotografia comercial'}. Composição: ${(img.composition_rules||[]).join(', ')}. Tratamento: ${img.filters||'limpo profissional'}.`;

const systemPrompt = `És um estratega de conteúdo sénior e diretor de arte para ${bsp.brand_name}. Crias carrosséis que param o scroll e são publicáveis diretamente no feed de uma marca premium.

ESCREVE SEMPRE EM PORTUGUÊS EUROPEU (pt-PT). Nunca em pt-BR, nunca em inglês.

IDENTIDADE DE MARCA:
Tom de voz: ${(tov.adjectives||[]).join(', ')}
FAZER: ${(tov.do||[]).join('; ')}
NÃO FAZER: ${(tov.dont||[]).join('; ')}
Referências de voz: ${(tov.sample_phrases||[]).join(' | ')}

IDENTIDADE VISUAL:
${styleAnchor}

REGRAS DO CARROSSEL:
Slide 1 (HOOK VISUAL): Uma afirmação ousada, pergunta provocadora, ou facto surpreendente que faz o utilizador parar e deslizar. Máx 8 palavras no título. SEM "Introdução" ou "Bem-vindo". O primeiro slide é a razão pela qual alguém desliza — tem de ser impossível de ignorar.
Slides do meio: UMA ideia por slide. Título curto e impactante (máx 6 palavras). Corpo máx 2 frases — direto ao ponto. Progressão narrativa real: cada slide constrói sobre o anterior.
Último slide (CTA): O que o utilizador deve fazer AGORA? CTA claro, específico, com urgência ou benefício.

PROGRESSÃO NARRATIVA — o carrossel deve ter uma estrutura de storytelling:
- Slide 1: Cria tensão ou curiosidade
- Slides 2-N-1: Resolve progressivamente, constrói conhecimento ou demonstra transformação
- Último: Convida à ação com benefício claro

CONCEITO VISUAL POR SLIDE — exatamente 3 frases:
Frase 1: Estilo fotográfico e sujeito com especificidade de materiais e posição.
Frase 2: Iluminação — key light (direção, tipo, temperatura Kelvin, ex: 45° superior esquerdo, softbox grande, 5500K); especificação de câmara (focal length mm, abertura f/).
Frase 3: "As ÚNICAS cores presentes são: primária ${p.primary||'N/A'} como [papel], secundária ${p.secondary||'N/A'} como [papel], accent ${p.accent||'N/A'} como [papel]. ${(img.composition_rules||['composição profissional']).join(', ')}. Tratamento: ${img.filters||'limpo profissional'}."

OUTPUT — JSON válido apenas, sem markdown:
{
  "slides": [
    {
      "slide_number": 1,
      "title": "...",
      "body": "...",
      "visual_concept": "brief de imagem de 3 frases com specs de iluminação e hex codes exatos"
    }
  ],
  "caption": "legenda para o feed (em pt-PT)",
  "hashtags": ["#hashtag_especifica_ao_nicho"]
}`;

const userMessage = `Cria um carrossel de ${inputs.numSlides} slides para ${inputs.platform} sobre: ${inputs.topic}`;
const payload = {
  model: 'gpt-4o',
  max_tokens: 4000,
  response_format: { type: 'json_object' },
  messages: [{ role: 'system', content: systemPrompt }, { role: 'user', content: userMessage }]
};
return [{ json: { payload } }];

const rawText = $input.first().json.choices?.[0]?.message?.content || '';
if (!rawText) throw new Error('OpenAI empty');
let r; try { r = JSON.parse(rawText); } catch(e) { throw new Error('Parse failed: ' + rawText.slice(0,200)); }
return [{ json: { slides: r.slides || [], caption: r.caption || '', hashtags: r.hashtags || [] } }];

const splitSlides = $('Split Slides').all();
const imageResults = $input.all();
const { caption, hashtags } = $('Parsear Resultado').first().json;
const slides = splitSlides.map((s, i) => {
  const imgData = imageResults[i]?.json?.data?.[0];
  const image_url = imgData?.url || (imgData?.b64_json ? `data:image/png;base64,${imgData.b64_json}` : '');
  return { ...s.json, image_url };
});
return [{ json: { slides, caption, hashtags } }];

const slide = $input.first().json;
const rawBsp = $('Buscar BSP Supabase').first().json;
const bsp = Array.isArray(rawBsp) ? rawBsp[0] : rawBsp;
const p = bsp?.palette || {};
const img = bsp?.imagery_style || {};

const styleAnchor = bsp?.style_anchor_prompt ||
  `MARCA: ${bsp?.brand_name||''}. PALETA: primária ${p.primary||'N/A'}, secundária ${p.secondary||'N/A'}, accent ${p.accent||'N/A'}, fundo ${p.background||'N/A'}. IMAGEM: ${img.description||'fotografia comercial profissional'}. COMPOSIÇÃO: ${(img.composition_rules||[]).join(', ')||'profissional'}. TRATAMENTO: ${img.filters||'limpo nítido profissional'}.`;

const visualConcept = slide.visual_concept || `${slide.title||''}: ${slide.body||''}`;

